module top_module(Q, CLK, RST, LOAD, D);output [3:0] Q;
  input CLK, RST, LOAD;
  input [3:0] D;

  reg [3:0] count;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RST) begin
      count <= 4'b0000;
    end
    else if (LOAD) begin
      count <= D;
    end
    else begin
      count <= count + 1;
    end
  end

  assign Q = count;

endmodule
